// --- 资源注册 ---

server.resource(
  'pc-dmis-status',
  'pc-dmis://status',
  async (uri) => ({
    contents: [{
      uri: uri.href,
      text: JSON.stringify(ctrl.getStatus(), null, 2),
      mimeType: 'application/json',
    }]
  })
);

// ============================================================
// 入口
// ============================================================

async function runStdio() {
  const transport = new StdioServerTransport();
  await server.connect(transport);
  console.error('[pc-dmis-mcp] stdio 模式已启动');
}

async function runSSE(port) {
  // 简单的 SSE HTTP 服务器
  let transport = null;

  const app = http.createServer(async (req, res) => {
    const url = new URL(req.url, `http://${req.headers.host}`);

    if (url.pathname === '/sse') {
      transport = new SSEServerTransport('/messages/', res);
      res.writeHead(200, {
        'Content-Type': 'text/event-stream',
        'Cache-Control': 'no-cache',
        'Connection': 'keep-alive',
        'Access-Control-Allow-Origin': '*',
      });
      await server.connect(transport);
      return;
    }

    if (url.pathname === '/messages/' && req.method === 'POST') {
      if (transport) {
        await transport.handlePostMessage(req, res);
      } else {
        res.writeHead(404);
        res.end('No active SSE connection');
      }
      return;
    }

    // Health check
    if (url.pathname === '/health') {
      res.writeHead(200, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ status: 'ok', server: 'pc-dmis-server' }));
      return;
    }

    res.writeHead(404);
    res.end('Not Found');
  });

  app.listen(port, '127.0.0.1', () => {
    console.error(`[pc-dmis-mcp] SSE 模式已启动，端口 ${port}`);
  });
}

